mbr.copysrc:
     /* =================================================================== */
     /*                                                                     */
     /*  Documentation:                                                     */
     /*                                                                     */
     /*  Utility . . . : FNDRPLSTR                                          */
     /*  Object  . . . : A_INSTALL  (PGM)                                   */
     /*  Source member : A_INSTALL                                          */
     /*  Source type . : CLLE                                               */
     /*  Description   : FNDRPLSTR - Installer                              */
     /*  Author  . . . : Thomas Raddatz   <thomas.raddatz@tools400.de>      */
     /*                                                                     */
     /* =================================================================== */
     /*                                                                     */
     /*  This software is free software, you can redistribute it and/or     */
     /*  modify it under the terms of the GNU General Public License (GPL)  */
     /*  as published by the Free Software Foundation.                      */
     /*                                                                     */
     /*  See GNU General Public License for details.                        */
     /*          http://www.opensource.org                                  */
     /*          http://www.opensource.org/licenses/gpl-license.html        */
     /*                                                                     */
     /* =================================================================== */
     /*  History:                                                           */
     /*                                                                     */
     /*  Datum       Name           nderung                                 */
     /*  ----------  ------------  ---------------------------------------  */
     /*                                                                     */
     /* =================================================================== */
     /*   >>PRE-COMPILER<<                                                  */
     /*     >>CRTCMD<<    CRTBNDCL  PGM(QTEMP/&OB) +                        */
     /*                             SRCFILE(&SL/&SF) SRCMBR(&SM);           */
     /*     >>IMPORTANT<<                                                   */
     /*       >>PARM<<    OPTION(*EVENTF);                                  */
     /*     >>END-IMPORTANT<<                                               */
     /*     >>EXECUTE<<                                                     */
     /*     >>CMD<<       CALL   PGM(QTEMP/A_INSTALL) +                     */
     /*                          PARM('*CURRENT' '&SF' '&LI' 'GER');        */
     /*     >>CMD<<       DLTPGM PGM(QTEMP/A_INSTALL);                      */
     /*   >>END-PRE-COMPILER<<                                              */
     /* =================================================================== */
             PGM        PARM(&TGTRLS &SRCFILE &TOLIB &LNG &TAGSREQ)

             DCL        VAR(&TGTRLS   ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&SRCFILE  ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&TOLIB    ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&LNG      ) TYPE(*CHAR) LEN( 3)
             DCL        VAR(&TAGSREQ  ) TYPE(*CHAR) LEN(10)

             DCL        VAR(&SRCLIB   ) TYPE(*CHAR) LEN(10)

             DCL        VAR(&CRTMSGF  ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&MSGF     ) TYPE(*CHAR) LEN(10) VALUE('FNDRPLSTR')
             DCL        VAR(&PNLGRP   ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&CMD      ) TYPE(*CHAR) LEN(10)

             CHGVAR     VAR(&SRCLIB) VALUE(&TOLIB   )

     /* -------------------------------- */
     /*  Delete old objects              */
     /* -------------------------------- */
             DLTCMD    CMD(&TOLIB/FNDRPLSTR)
             MONMSG     MSGID(CPF2105)

             DLTPGM    PGM(&TOLIB/FNDRPLR1)
             MONMSG     MSGID(CPF2105)

             DLTMOD    MODULE(&TOLIB/FNDRPLR1)
             MONMSG     MSGID(CPF2105)

             DLTMOD    MODULE(&TOLIB/PRGMTRR1)
             MONMSG     MSGID(CPF2105)

             DLTPNLGRP PNLGRP(&TOLIB/FNDRPLPG)
             MONMSG     MSGID(CPF2105)

             DLTMSGF    MSGF(&TOLIB/&MSGF)
             MONMSG     MSGID(CPF2105)

             RMVMSG     PGMQ(*SAME (*)) CLEAR(*ALL)

     /* -------------------------------- */
     /*  Create message file             */
     /* -------------------------------- */
             IF         COND(&LNG *EQ 'ENG') THEN(DO)
                CHGVAR     VAR(&CRTMSGF) VALUE('A_MSG_ENG')
                CHGVAR     VAR(&PNLGRP ) VALUE('FNDRPLPE')
                CHGVAR     VAR(&CMD    ) VALUE('FNDRPLSTRE')
             ENDDO
             ELSE       CMD(DO)
                CHGVAR     VAR(&CRTMSGF) VALUE('A_MSG_GER')
                CHGVAR     VAR(&PNLGRP ) VALUE('FNDRPLPG')
                CHGVAR     VAR(&CMD    ) VALUE('FNDRPLSTRG')
             ENDDO

             CRTMSGF    MSGF(&TOLIB/&MSGF) +
                          TEXT('Find and Replace Strings')

             CRTCLPGM   PGM(QTEMP/&CRTMSGF) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*PGM) +
                          OPTION(*LSTDBG) +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(&CRTMSGF  ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

             CALL       PGM(QTEMP/&CRTMSGF) PARM(&TOLIB)
             DLTPGM     PGM(QTEMP/&CRTMSGF)

     /* -------------------------------- */
     /*  Create modules                  */
     /* -------------------------------- */
             CRTRPGMOD  MODULE(&TOLIB/FNDRPLR1) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*MODULE) +
                          TEXT(*SRCMBRTXT) +
                          DBGVIEW(*LIST) +
                          TRUNCNBR(*NO) +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(FNDRPLR1) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

             CRTRPGMOD MODULE(&TOLIB/PRGMTRR1) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*MODULE) +
                          TEXT(*SRCMBRTXT) +
                          DBGVIEW(*LIST) +
                          TRUNCNBR(*NO) +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(PRGMTRR1) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create programs                 */
     /* -------------------------------- */
             CRTPGM     PGM(&TOLIB/FNDRPLSTR) +
                          MODULE(&TOLIB/FNDRPLR1  +
                                 &TOLIB/PRGMTRR1) +
                          ENTMOD(&TOLIB/FNDRPLR1) +
                          BNDSRVPGM(*LIBL/BASICS1  +
                                    *LIBL/RTVMBRL) +
                          DETAIL(*BASIC) +
                          ACTGRP(*NEW) +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(FNDRPLSTR ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create panel groups             */
     /* -------------------------------- */
             CRTPNLGRP PNLGRP(&TOLIB/FNDRPLSTRP) +
                          SRCFILE(&SRCLIB/&SRCFILE) +
                          SRCMBR(&PNLGRP)
             DLTSPLF    FILE(&PNLGRP   ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create commands                 */
     /* -------------------------------- */
             CRTCMD     CMD(&TOLIB/FNDRPLSTR) +
                          PGM(&TOLIB/FNDRPLSTR) +
                          SRCFILE(&SRCLIB/&SRCFILE) +
                          SRCMBR(&CMD) +
                          MSGF(&TOLIB/FNDRPLSTR) +
                          HLPPNLGRP(&TOLIB/FNDRPLSTRP) +
                          HLPID(FNDRPLSTR)
             DLTSPLF    FILE(&CMD      ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Delete obsolete objects         */
     /* -------------------------------- */
             DLTMOD    MODULE(&TOLIB/FNDRPLR1)
             DLTMOD    MODULE(&TOLIB/PRGMTRR1)

             ENDPGM

             PGM        PARM(&LI)

             DCL        VAR(&LI) TYPE(*CHAR) LEN(10)

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD f r Message-ID :   FRS0001                    */
     /* Searching member &1.                                        */
     /* ----------------------------------------------------------- */

             RMVMSGD MSGID(FRS0001) MSGF(&LI/FNDRPLSTR)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(FRS0001) +
                MSGF(&LI/FNDRPLSTR) +
                MSG(+
'Searching member &1.'                                                +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 010) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD f r Message-ID :   FRS0002                    */
     /* Applied &1 changes to member &2 in file &4/&3.              */
     /* ----------------------------------------------------------- */

             RMVMSGD MSGID(FRS0002) MSGF(&LI/FNDRPLSTR)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(FRS0002) +
                MSGF(&LI/FNDRPLSTR) +
                MSG(+
'Applied &1 changes to member &2 in file &4/&3.'                      +
                ) +
                SEV(00) +
                FMT( +
                    (*DEC 010 0) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD f r Message-ID :   FRS0003                    */
     /* No matches found in member &2 in file &4/&3.                */
     /* ----------------------------------------------------------- */

             RMVMSGD MSGID(FRS0003) MSGF(&LI/FNDRPLSTR)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(FRS0003) +
                MSGF(&LI/FNDRPLSTR) +
                MSG(+
'No matches found in member &2 in file &4/&3.'                        +
                ) +
                SEV(00) +
                FMT( +
                    (*DEC 010 0) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD f r Message-ID :   FRS0004                    */
     /* Retrieving member list ...                                  */
     /* ----------------------------------------------------------- */

             RMVMSGD MSGID(FRS0004) MSGF(&LI/FNDRPLSTR)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(FRS0004) +
                MSGF(&LI/FNDRPLSTR) +
                MSG(+
'Retrieving member list ...'                                          +
                ) +
                SEV(00) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD f r Message-ID :   FRS0005                    */
     /* Searching                                                   */
     /* ----------------------------------------------------------- */

             RMVMSGD MSGID(FRS0005) MSGF(&LI/FNDRPLSTR)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(FRS0005) +
                MSGF(&LI/FNDRPLSTR) +
                MSG(+
'Searching'                                                           +
                ) +
                SEV(00) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

             RCLRSC LVL(*)

             ENDPGM

             PGM        PARM(&LI)

             DCL        VAR(&LI) TYPE(*CHAR) LEN(10)

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD f r Message-ID :   FRS0001                    */
     /* Searching member &1.                                        */
     /* ----------------------------------------------------------- */

             RMVMSGD MSGID(FRS0001) MSGF(&LI/FNDRPLSTR)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(FRS0001) +
                MSGF(&LI/FNDRPLSTR) +
                MSG(+
'Durchsuche Teildatei &1.'                                            +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 010) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD f r Message-ID :   FRS0002                    */
     /* Applied &1 changes to member &2 in file &4/&3.              */
     /* ----------------------------------------------------------- */

             RMVMSGD MSGID(FRS0002) MSGF(&LI/FNDRPLSTR)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(FRS0002) +
                MSGF(&LI/FNDRPLSTR) +
                MSG(+
'&1  nderungen in Teildatei &2 in Datei &4/&3 durchgef hrt.'          +
                ) +
                SEV(00) +
                FMT( +
                    (*DEC 010 0) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD f r Message-ID :   FRS0003                    */
     /* No matches found in member &2 in file &4/&3.                */
     /* ----------------------------------------------------------- */

             RMVMSGD MSGID(FRS0003) MSGF(&LI/FNDRPLSTR)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(FRS0003) +
                MSGF(&LI/FNDRPLSTR) +
                MSG(+
'Keine Fundstellen in Teildatei &2 in Datei &4/&3.'                   +
                ) +
                SEV(00) +
                FMT( +
                    (*DEC 010 0) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD f r Message-ID :   FRS0004                    */
     /* Retrieving member list ...                                  */
     /* ----------------------------------------------------------- */

             RMVMSGD MSGID(FRS0004) MSGF(&LI/FNDRPLSTR)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(FRS0004) +
                MSGF(&LI/FNDRPLSTR) +
                MSG(+
'Abrufen Liste der Teildateien ...'                                   +
                ) +
                SEV(00) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD f r Message-ID :   FRS0005                    */
     /* Searching                                                   */
     /* ----------------------------------------------------------- */

             RMVMSGD MSGID(FRS0005) MSGF(&LI/FNDRPLSTR)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(FRS0005) +
                MSGF(&LI/FNDRPLSTR) +
                MSG(+
'Durchsuche'                                                          +
                ) +
                SEV(00) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

             RCLRSC LVL(*)

             ENDPGM

**free
/if NOT defined(CEELIB)
/define CEELIB

//  Test for Omitted Argument (CEETSTA) API
dcl-pr CEETSTA extproc('CEETSTA');
  io_isPresent int(10);
  i_argNum     int(10) const;
  o_fc         char(12) options(*omit);
end-pr;

//  Get String Information (CEEGSI) API
dcl-pr CEEGSI extproc('CEEGSI');
  i_posn     int(10) const;
  o_datatype int(10);
  o_curlen   int(10);
  o_maxlen   int(10);
  o_fb       char(12) options(*omit);
end-pr;

//  Reference fields for CEEGSI API
dcl-ds strInf_t based(pDummy) qualified;
  datatype int(10);
  curlen   int(10);
  maxlen   int(10);
end-ds;

//  Register Activation Group Exit Procedure (CEE4RAGE) API
dcl-pr CEE4RAGE extproc('CEE4RAGE');
  i_pProc pointer(*proc) const;
  fc      char(12) options(*omit);
end-pr;

//  Logarithm base 10 (double float)
dcl-pr CEESDLG1 extproc('CEESDLG1');
  i_value  float(8) const;
  o_result float(8);
end-pr;

//  Register Call Stack Entry Termination User Exit Procedure (CEERTX)
dcl-pr CEERTX extproc('CEERTX');
  i_procPtr  pointer(*proc) const;
  i_rtxToken pointer options(*omit) const;
  o_fc       char(12) options(*omit);
end-pr;

//  Unregister Call Stack Entry Termination User Exit Procedure (CEEUTX)
dcl-pr CEEUTX extproc('CEEUTX');
  i_procPtr pointer(*proc) const;
  o_fc      char(12) options(*omit);
end-pr;

/endif

**free
/if not defined(COPYRIGHT_DSPEC)
ctl-opt copyright('V1.3 - 06.06.2026 - mailto: thomas.raddatz@tools400.de');
/eof
/endif
dcl-c FNDRPLSTR_VERSION '1.3';
dcl-c FNDRPLSTR_DATE '06.06.2026';

**free
/if NOT defined(errCode_t)
/define errCode_t
//===============================================================*
//  API error code                                               *
//===============================================================*
dcl-ds errCode_t qualified based(pDummy);
  bytPrv     int(10);
  bytAvl     int(10);
  excID      char(7);
  reserved_1 char(1);
  excDta     char(256);
end-ds;

/endif

**free
/if NOT defined(msg_t)
/define msg_t
// ============================================================= *
//   Message structure                                           *
// ============================================================= *

dcl-ds msg_t qualified based(pDummy);
  ID   likeds(msgID_t);
  data char(512);
  type char(10);
  file char(10);
  lib  char(10);
end-ds;

dcl-ds msgID_t qualified based(pDummy);
  prefix char(3);
  nbr    zoned(4);
end-ds;

/endif

**free
/if NOT defined(qObj_t)
/define qObj_t
// ============================================================= *
//   Qualified object name                                       *
//===============================================================*

dcl-ds qObj_t qualified based(pDummy);
  name char(10);
  lib  char(10);
end-ds;

/endif

**free
