             CMD        PROMPT('Find and Replace Strings')

             PARM       KWD(FILE)              +
                        MIN(1)                 +
                        TYPE(QUAL1)            +
                        PROMPT('File')

             PARM       KWD(MBR)               +
                        TYPE(*GENERIC)         +
                        MIN(1)                 +
                        SPCVAL((*FIRST)        +
                               (*ALL))         +
                        PROMPT('Member')

             PARM       KWD(VALUES)            +
                        TYPE(ELEM1)            +
                        MIN(1)                 +
                        MAX(10)                +
                        PROMPT('Find and replace')

             PARM       KWD(CASE)              +
                        TYPE(*CHAR)            +
                        LEN(10)                +
                        MIN(0)                 +
                        DFT(*IGNORE)           +
                        RSTD(*YES)             +
                        VALUES(*IGNORE         +
                               *MATCH )        +
                        PROMPT('Kind of match')

             PARM       KWD(WILDCARD)          +
                        TYPE(*CHAR)            +
                        LEN(1)                 +
                        MIN(0)                 +
                        VARY(*YES *INT2)       +
                        DFT(*NONE)             +
                        SPCVAL((*NONE ''))     +
                        PROMPT('Wildcard character')

 QUAL1:      QUAL       TYPE(*NAME)            +
                        LEN(10)                +
                        MIN(1)
             QUAL       TYPE(*NAME)            +
                        LEN(10)                +
                        DFT(*LIBL)             +
