dcl-c cPrgMtr_White X'23';
dcl-c cPrgMtr_Red X'29';
dcl-c cPrgMtr_Turqoise X'31';
dcl-c cPrgMtr_Yellow X'33';
dcl-c cPrgMtr_Pink X'39';
dcl-c cPrgMtr_Blue X'3B';

